// Middleware to check if user is authenticated (pre-MFA)
function requirePreAuth(req, res, next) {
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Authentication required. Please log in first.' });
  }
  next();
}

// Middleware to check if MFA is verified
function requireFullAuth(req, res, next) {
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Authentication required.' });
  }
  if (!req.session.mfaVerified) {
    return res.status(403).json({ error: 'MFA verification required.' });
  }
  next();
}

