app.post('/auth/mfa/verify', requirePreAuth, verifyCodeLimiter, (req, res) => {
  const { code } = req.body;

  if (!code) {
    return res.status(400).json({ error: 'Verification code is required.' });
  }

  const sanitizedCode = sanitizeCode(code);

  if (sanitizedCode.length !== MFA_CODE_LENGTH) {
    return res.status(400).json({ error: `Code must be exactly ${MFA_CODE_LENGTH} digits.` });
  }

  const mfaEntry = mfaStore.get(req.sessionID);

  if (!mfaEntry) {
    return res.status(400).json({
      error: 'No verification code found. Please request a new code.'
    });
  }

  // Check if code has expired
  if (Date.now() - mfaEntry.createdAt > MFA_CODE_EXPIRY_MS) {
    mfaStore.delete(req.sessionID);
    return res.status(400).json({
      error: 'Verification code has expired. Please request a new code.'
    });
  }

  // Check attempt limit
  if (mfaEntry.attempts >= MAX_VERIFICATION_ATTEMPTS) {
    mfaStore.delete(req.sessionID);
    return res.status(429).json({
      error: 'Maximum verification attempts exceeded. Please request a new code.'
    });
  }

  // Increment attempts
  mfaEntry.attempts += 1;

  // Verify code using constant-time comparison on hashes
  const inputHash = hashCode(sanitizedCode);
  const isValid = secureCompare(inputHash, mfaEntry.codeHash);

  if (!isValid) {
    const remainingAttempts = MAX_VERIFICATION_ATTEMPTS - mfaEntry.attempts;
    return res.status(401).json({
      error: 'Invalid verification code.',
      remainingAttempts
    });
  }

  // Code is valid - mark as verified and clean up
  mfaEntry.verified = true;
  mfaStore.delete(req.sessionID);

  // Update session
  req.session.mfaVerified = true;
  req.session.mfaPending = false;
  req.session.mfaVerifiedAt = Date.now();

  // Regenerate session ID to prevent session fixation
  req.session.regenerate((err) => {
    if (err) {
      console.error('Session regeneration error:', err);
      return res.status(500).json({ error: 'Authentication error.' });
    }

    // Restore session data after regeneration
    req.session.userId = mfaEntry.userId;
    req.session.mfaVerified = true;
    req.session.mfaVerifiedAt = Date.now();

    res.json({
      message: 'MFA verification successful. You are now fully authenticated.',
      authenticated: true
    });
  });
});

